class MemoizedComponent:
    def __init__(self, items):
        self.items = items
        self.memoized = {}
    def update(self):
        # Update the array reference
        self.items = [1, 2, 4]
    def render(self):
        # Render the component
        if self.memoized.get(tuple(self.items)) is None:
            self.memoized[tuple(self.items)] = 'Rendered'
            return self.memoized[tuple(self.items)]
        else:
            return self.memoized[tuple(self.items)]
